  }
  return '';
}

function num(v) {
  const s = text(v).replace(/\s/g, '').replace(/[^0-9,.]/g, '').replace(',', '.');
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

function hasAny(s, words) {
