function qualityGate(j) {
  const hotel = text(pick(j, ['–Э–∞–Ј–≤–∞–љ–Є–µ', '–Ю—В–µ–ї—М', 'hotel', 'hotel_name', 'name', 'title']));
  const url = text(pick(j, ['–°—Б—Л–ї–Ї–∞', 'source_url', 'url', 'link', 'URL']));
  const request = text(pick(j, ['–Ч–∞–њ—А–Њ—Б', 'originalRequest', 'request', '–Ш—Б—Е–Њ–і–љ—Л–є –Ј–∞–њ—А–Њ—Б']));
  const priceRaw = pick(j, ['–¶–µ–љ–∞', 'price', '–°—В–Њ–Є–Љ–Њ—Б—В—М', 'amount']);
  const price = num(priceRaw);

  let score = 10;
  const risks = [];

  let priceConfidence = 'needs_check';

  if (!url) {
    score -= 3;
    risks.push('–љ–µ—В source_url');
    priceConfidence = 'unknown';
  }

  if (price === null) {
    score -= 4;
    risks.push('—Ж–µ–љ–∞ –љ–µ —А–∞—Б–њ–Њ–Ј–љ–∞–љ–∞');
    priceConfidence = 'unknown';
  }

  if (price !== null && price <= 0) {
    score -= 6;
    risks.push('—Ж–µ–љ–∞ –љ–µ–Ї–Њ—А—А–µ–Ї—В–љ–∞—П');
    priceConfidence = 'suspicious';
  }

  if (price !== null && price > 0 && price < 40000) {
    score -= 5;
    risks.push('—Ж–µ–љ–∞ –≤—Л–≥–ї—П–і–Є—В –њ–Њ–і–Њ–Ј—А–Є—В–µ–ї—М–љ–Њ –љ–Є–Ј–Ї–Њ–є');
    priceConfidence = 'suspicious';
  }

  if (url && hasAny(url, ['search?', 'google.', 'yandex.', 'text=', 'query='])) {
    score -= 2;
    risks.push('—Б—Б—Л–ї–Ї–∞ –њ–Њ—Е–Њ–ґ–∞ –љ–∞ –њ–Њ–Є—Б–Ї, –∞ –љ–µ –њ—А—П–Љ–Њ–є –Є—Б—В–Њ—З–љ–Є–Ї');
    if (priceConfidence !== 'suspicious') priceConfidence = 'needs_check';
  }

  const allText = [hotel, request, JSON.stringify(j)].join(' ');

  if (hasAny(allText, ['aqua', '–∞–Ї–≤–∞', 'kids', '–і–µ—В', 'family', '—Б–µ–Љ–µ–є–љ', 'animation', '–∞–љ–Є–Љ–∞—Ж'])) {
    score -= 2;
    risks.push('–µ—Б—В—М –њ—А–Є–Ј–љ–∞–Ї–Є —Б–µ–Љ–µ–є–љ–Њ–≥–Њ/–і–µ—В—Б–Ї–Њ–≥–Њ –Њ—В–µ–ї—П');
  }

  if (hasAny(allText, ['large resort', 'huge', '–±–Њ–ї—М—И–Њ–є –Ї–Њ–Љ–њ–ї–µ–Ї—Б', '–Љ–љ–Њ–≥–Њ –Ї–Њ—А–њ—Г—Б–Њ–≤', '–Љ—Г—А–∞–≤–µ–є–љ–Є–Ї'])) {
    score -= 3;
    risks.push('–µ—Б—В—М —А–Є—Б–Ї –Љ—Г—А–∞–≤–µ–є–љ–Є–Ї–∞');
  }

  if (hasAny(allText, ['old reviews', '–љ–Є–Ј–Ї–Є–є —А–µ–є—В–Є–љ–≥', '–њ–ї–Њ—Е–Є–µ –Њ—В–Ј—Л–≤—Л', 'rating 6', 'rating: 6'])) {
    score -= 2;
    risks.push('–µ—Б—В—М —А–Є—Б–Ї —Б–ї–∞–±—Л—Е –Њ—В–Ј—Л–≤–Њ–≤');
  }

  if (hasAny(allText, ['no meal', '–±–µ–Ј –њ–Є—В–∞–љ–Є—П', '–њ–Є—В–∞–љ–Є–µ –љ–µ —Г–Ї–∞–Ј–∞–љ–Њ', 'unclear meal'])) {
    score -= 1;
    risks.push('–њ–Є—В–∞–љ–Є–µ –љ–µ –њ–Њ–і—В–≤–µ—А–ґ–і–µ–љ–Њ');
  }

  score = Math.max(0, Math.min(10, score));

  let riskLevel = 'low';
  if (score < 8 || risks.length >= 2) riskLevel = 'medium';
  if (score < 6 || priceConfidence === 'suspicious' || risks.length >= 4) riskLevel = 'high';

  let decision = 'recommend';
  let rejectReason = '';

  if (riskLevel === 'high' || score < 6) {
    decision = 'reject';
    rejectReason = risks.join('; ') || '–Ї–∞—З–µ—Б—В–≤–Њ –≤–∞—А–Є–∞–љ—В–∞ –љ–µ –њ–Њ–і—В–≤–µ—А–ґ–і–µ–љ–Њ';
  } else if (score < 8 || priceConfidence !== 'confirmed') {
    decision = 'backup';
  }

  const status = decision === 'recommend'
    ? '–†–µ–Ї–Њ–Љ–µ–љ–і–Њ–≤–∞—В—М'
    : decision === 'backup'
      ? '–Ч–∞–њ–∞—Б–љ–Њ–є –≤–∞—А–Є–∞–љ—В / —В—А–µ–±—Г–µ—В—Б—П –њ—А–Њ–≤–µ—А–Ї–∞'
      : '–Ю—В–Ї–ї–Њ–љ–Є—В—М';

  return {
    ...j,

    '–°—В–∞—В—Г—Б –њ—А–Њ–≤–µ—А–Ї–Є': status,
    'Score': score,
    'Risk Level': riskLevel,
    'Reject Reason': rejectReason,
    'Price Confidence': priceConfidence,
    'Source URL': url,
    'Checked At': new Date().toISOString(),

    status,
    score,
    risk_level: riskLevel,
    reject_reason: rejectReason,
    price_confidence: priceConfidence,
    source_url: url,
    checked_at: new Date().toISOString()
  };
}

